function ListNode(val, next) {
    this.val = (val===undefined ? 0 : val)
    this.next = (next===undefined ? null : next)
}

function mergeInBetween(list1, a, b, list2) {
    let prev = null;
    let curr = list1;
    let index = 0;

    while(curr !== null) {
        if(index === a) {
            let last = list2;
            while(last.next !== null) {
                last = last.next;
            }
            prev.next = list2;
            last.next = curr.next;
            break;
        } else if(index > a && index < b) {
            curr = curr.next;
        } else {
            prev = curr;
            curr = curr.next;
        }
        index++;
    }
    return list1;
}
```


    1. Initialize variables `prev` as null, `curr` as the head of `list1`, and `index` as 0.
2. Iterate `curr` through the nodes of `list1`.
3. When the `index` is equal to `a`, set `last` as the head of `list2`, and find the last node in `list2`. Then, link `prev` to the head of `list2`, and link the last node of `list2` to the next node of `curr`. Break the loop.
4. If the `index` is between `a` and `b`, move `curr` to the next node directly.
5. Else, set `prev` as `curr`, and move `curr` to the next node.
6. Increment `index`.
7. Return the modified `list1`.

