public class ListNode {
    int val;
    ListNode next;
    ListNode() {}
    ListNode(int val) { this.val = val; }
    ListNode(int val, ListNode next) { this.val = val; this.next = next; }
}

public ListNode mergeInBetween(ListNode list1, int a, int b, ListNode list2) {
    ListNode prev = null;
    ListNode curr = list1;
    int index = 0;

    while(curr != null) {
        if(index == a) {
            ListNode temp = curr;
            curr = curr.next;
            ListNode last = list2;
            while(last.next != null) {
                last = last.next;
            }
            prev.next = list2;
            last.next = curr;
        } else if(index > a && index < b) {
            curr = curr.next;
        } else {
            prev = curr;
            curr = curr.next;
        }
        index++;
    }
    return list1;
}
```

